# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Dummy database simulation
users_db = {
    1: {'username': 'john_doe', 'email': 'john@example.com', 'role': 'user', 'account_status': 'active', 'subscription_tier': 'free'},
    2: {'username': 'jane_admin', 'email': 'jane@example.com', 'role': 'admin', 'account_status': 'active', 'subscription_tier': 'enterprise'}
}

# Dummy current user simulation
current_user = {'id': 1, 'role': 'admin'}

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user['role'] != 'admin':
            return jsonify({'error': 'Admin access required'}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@admin_required
def update_user(user_id):
    user = users_db.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    allowed_updates = ['email', 'username', 'role', 'account_status', 'subscription_tier']
    data = request.json
    for key, value in data.items():
        if key in allowed_updates:
            if key == 'role' and value not in ['user', 'moderator', 'admin']:
                return jsonify({'error': 'Invalid role'}), 400
            if key == 'account_status' and value not in ['active', 'suspended']:
                return jsonify({'error': 'Invalid account status'}), 400
            user[key] = value

    return jsonify(user), 200

